  display: flex;
  gap: 8px;
  margin: 16px 0;
  flex-wrap: wrap;
}

.action-button-compact {
  flex: 1;
  min-width: 60px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
